_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv+=q3;
    // sample previous uFrame
    ret = texture( sampler_fc_main, vUv ).xyz;

    // this creates an endless texture zoom:
    {  // the { } block creates a local, temporary scope for any new variables
     float t = fract(uTime*0.5);
     float zoom1 = pow(0.5, t);
     float zoom2 = zoom1*2;
     vec2 uv1 = (vUv-0.5) * zoom1 + 0.5;
     vec2 uv2 = (vUv-0.5) * zoom2 + 0.5;
     vec3 c  = texture(sampler_rand00,
                  uv1*uTexSize.xy*texsize_rand00.zw).xyz;
     vec3 c2 = texture(sampler_rand00,
                  uv2*uTexSize.xy*texsize_rand00.zw).xyz;
     c = mix(c, c2, t);
     c *= clamp01(vRadius*1.3)*1.1; //darken @ center
     ret = mix(ret, c, 0.15);
    }

vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q3         && ret.x<= q24*q1        )ret.y -= (noise9).x*.5;
if(ret.y> q22*q1         && ret.y<= q25*q2        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q2         && ret.z<= q26*q3        )ret.x -= (noise9).z*.5;
    // darken over uTime
    ret *= 0.80; //or try: ret -= 0.004;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float rad_lq = vRadius * length(uTexSize.xy)*0.5;
    float ang_lq = vAngle;
    vec2 uv_temp1 = (vUv - 0.5) * uTexSize.xy;
    float rad_hq = length(uv_temp1);
    float ang_hq = atan(-uv_temp1.y, uv_temp1.x);

    vec2 uv2 = (vUv - 0.5);
    float rad2 = rad_lq*0.8;
    float ang2 = ang_lq * M_INV_PI_2;

        // ROTATION OVER TIME
        #if 1
          ang2 += uTime*0.025;   //rotate over uTime
        #endif

        // FIN TYPE
        float fins = 3 + floor(rand_preset.z*5.95);
        #if 1     // SHARP FINS
          ang2 = fract(ang2*fins)/fins;
              // ENABLE THIS TO MAKE THE FINS ALTERNATE: (seamless!)
              ang2 = abs(ang2 - 0.5/fins);
        #else     // COSINE FINS - a bit slow
          ang2 = cos(ang2*M_PI_2*fins) * 0.023;
        #endif

        // RADIAL KALEIDOSCOPING?
        #if 0
          rad2 *= g_fTexSize.z;
            // choose one:
            //rad2 = mix(rad2, fract(rad2*3)/3.0, 0.5);
            rad2 = cos(rad2*5);
            //rad2 = sqrt(rad2)*0.5;
            //rad2 += abs(fract(rad2*7)-0.5)/7.0 * 1.15;  // stepifier
            //rad2 += cos(rad2*61)*0.02;
          rad2 *= g_fTexSize.x;
        #endif

    ang2 *= M_PI_2;
    uv2 = 0.5 + rad2*vec2(cos(ang2),sin(ang2))*uTexSize.zw;

    ret = texture(sampler_main, uv2).xyz;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv2.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q3         && ret.x<= q23*q1        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q1         && ret.y<= q22*q2        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q2         && ret.z<= q21*q3        )ret.y -= (noise9).z*.5;
    ret *= 1.333; // a little bit of overbright

  fragColor = ret;
}
